import React from 'react';
// 1. Importing your Logo (Capital 'L' to match your file)
import Logo from './Logo.png'; 
// 2. Importing your Menu component
import Menu from './Menu'; 

function App() {
  return (
    <div style={{ 
      backgroundColor: '#000', 
      minHeight: '100vh', 
      color: '#fff', 
      fontFamily: 'Arial, sans-serif' 
    }}>
      
      {/* HEADER SECTION WITH LOGO */}
      <header style={{ 
        padding: '50px 20px', 
        textAlign: 'center', 
        borderBottom: '1px solid #1A1A1A' 
      }}>
        {/* The Logo Image */}
        <img 
          src={Logo} 
          alt="Àmí by T Logo" 
          style={{ 
            height: '160px', // Adjust this number if the logo is too big/small
            width: 'auto', 
            marginBottom: '15px',
            display: 'inline-block'
          }} 
        />
        
        <p style={{ 
          color: '#E07A5F', 
          letterSpacing: '5px', 
          textTransform: 'uppercase', 
          fontSize: '0.8rem',
          margin: 0
        }}>
          Taste and Style
        </p>
      </header>

      {/* MAIN CONTENT SECTION */}
      <main style={{ paddingBottom: '80px' }}>
        <Menu />
      </main>

      {/* FOOTER SECTION */}
      <footer style={{ 
        textAlign: 'center', 
        padding: '40px 20px', 
        borderTop: '1px solid #1A1A1A',
        color: '#444',
        fontSize: '0.75rem',
        letterSpacing: '2px'
      }}>
        <p>© 2026 ÀMÍ BY T | LAGOS, NIGERIA</p>
      </footer>
      
    </div>
  );
}

export default App;
